const Q_BIOLOGY_2021_MODEL_II=[{"id": "objective>Biology>2021-Model-II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following levels encompasses the rest?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">class </div>", "<div style=\"font-family:Cambria;font-size:17px;\">kingdom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phylum </div>", "<div style=\"font-family:Cambria;font-size:17px;\">species </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the biological classification system, the kingdom is the highest rank and it encompasses all other levels. The hierarchy of biological classification from highest to lowest is: Kingdom, Phylum, Class, Order, Family, Genus, Species. Therefore, the kingdom encompasses the rest.</div>", "topic": "LIVING ORGANISMS : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2021-Model-II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The group mollusca is characterized by the presence of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">jointed appendages </div>", "<div style=\"font-family:Cambria;font-size:17px;\">star-shaped bodies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">backbones </div>", "<div style=\"font-family:Cambria;font-size:17px;\">soft, non-segmented bodies </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The group Mollusca is characterized by soft, non-segmented bodies. Molluscs are a diverse group of invertebrates that includes squids, octopuses, clams, snails and slugs. They do not have jointed appendages, star-shaped bodies or backbones.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>2021-Model-II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A virus can sometime be regarded as a living organism because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">causes diseases in plants and animals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exists in a variety of shapes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reproduces in living cells </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is easily visible with an electron microscope </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A virus can sometimes be regarded as a living organism because it reproduces in living cells. Viruses are considered 'alive' because they possess genetic material, reproduce, and evolve through natural selection, but they lack the cell structure that is generally seen as the basic unit of life, hence they need to use the cellular machinery of other organisms to reproduce.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2021-Model-II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best describes a key difference between plant and animal nutrition?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Plants depend on external sources for food while animals manufacture their own food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plants take in oxygen and give out carbon dioxide only at night</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plants produce their own food through photosynthesis while animals feed on ready-made food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Animals excrete oxygen as waste while plants do not</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plants manufacture their own food using carbon dioxide, water, and sunlight through a process called photosynthesis, which is a form of autotrophic nutrition. Animals, on the other hand, are heterotrophs — they rely on consuming other organisms for their food. This is a fundamental difference between plant and animal nutrition.</div>", "topic": "LIVING ORGANISMS : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2021-Model-II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which feature would least help a seed to be carried away by the wind?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Paper-thin wings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Feather-like hairs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lightweight body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thick, spongy outer coat</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Seeds dispersed by wind need to be light and may have wings or fine hairs for buoyancy in air. A thick, spongy coat is more useful for water dispersal because it helps seeds float, so it would not help in wind dispersal.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2021-Model-II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best explains a common feature shared by both unicellular and multicellular organisms?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They both carry out essential life processes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They both have tissues and organs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They both reproduce only by binary fission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They both live in aquatic environments only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both unicellular and multicellular organisms carry out essential life processes such as respiration, nutrition, excretion, reproduction, and response to stimuli. In unicellular organisms, all functions occur within one cell, while multicellular organisms have specialized cells to carry out these processes. The other options do not apply to both types of organisms.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2021-Model-II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One most important characteristic of green plant is that they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">possess specialized sense organ </div>", "<div style=\"font-family:Cambria;font-size:17px;\">are usually motile </div>", "<div style=\"font-family:Cambria;font-size:17px;\">are autotrophic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">respond slowly to stimuli</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important characteristic of green plants is that they are autotrophic. Autotrophic organisms are capable of synthesizing their own food from inorganic substances using light or chemical energy. Green plants do this through a process called photosynthesis, where they use sunlight, carbon dioxide, and water to produce glucose and oxygen. The other options are not universally true for all green plants.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2021-Model-II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A serious disadvantage of complexity in higher organisms is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a high demand for food and energy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ability to function in many specialized roles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">little amount of energy dissipated in functioning </div>", "<div style=\"font-family:Cambria;font-size:17px;\">specialization of body parts </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A serious disadvantage of complexity in higher organisms is a high demand for food and energy. As organisms become more complex, their metabolic needs increase. They require more energy to maintain their complex structures and carry out their numerous functions. This energy comes from food. Therefore, complex organisms need a constant and abundant supply of food to meet their energy demands. The other options are not disadvantages but rather advantages or characteristics of complex organisms.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2021-Model-II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of a vestigial feature in the human body?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tailbone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Small intestine</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The human tailbone, or coccyx, is a vestigial structure. It is the remnant of a tail from our evolutionary ancestors and no longer serves its original function of aiding in balance and mobility. In some animals, such as monkeys, the tail is still functional.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2021-Model-II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs of organisms are photosynthetic?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Amoeba and Paramecium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Volvox and Rhizopus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas and Euglena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nostoc and Plasmodium </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas and Euglena are both photosynthetic organisms. Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the help of chlorophyll pigments. In this process, light energy is converted into chemical energy.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2021-Model-II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs of organisms exist as colonies?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Obelia and Euglena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pandorina and Volvox </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas and Amoeba </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydra and Spirogyra</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pandorina and Volvox are examples of organisms that exist as colonies. A colony is a group of organisms of the same species living together, usually for mutual benefit. In the case of Pandorina and Volvox, the individual organisms (cells) live together in a coordinated and interdependent manner.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2021-Model-II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Why is it easier to see black-and-white images than colored ones in very dim light?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rods are more sensitive to dim light and detect only black and white</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cones are more sensitive to dim light and detect only black and white</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The iris enlarges to allow colored light to enter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The lens becomes thicker to focus colored light on the retina</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In dim light, the amount of light that reaches the retina is reduced. The retina contains two types of photoreceptor cells - rods and cones. Cones are responsible for color vision and function best in relatively bright light. If the light is too dim, the cones may not be stimulated at all, making it difficult to see clearly. This is why the option 'too little light reaches the retina, so the cone may not be stimulated at all' is correct.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2021-Model-II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In active transport, molecules move against a concentration gradient, therefore</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">molecules move from a region of low concentration to a region of high concentration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">molecules move from a region of high concentration to a region of low concentration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the concentration gradient has little effect on the movement of molecules </div>", "<div style=\"font-family:Cambria;font-size:17px;\">molecules force their ways through special channels </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In active transport, molecules move against a concentration gradient. This means that the molecules move from a region of low concentration to a region of high concentration. <br/>  <img src=\"2021-Model-II/bio4.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "TRANSPORT : CHANNELS FOR TRANSPORTATION"}, {"id": "objective>Biology>2021-Model-II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following substance passes through the root cell membrane by osmosis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cell sap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon dioxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Osmosis is the process by which water molecules move from an area of high concentration to an area of low concentration, across a semi-permeable membrane. In the case of plant roots, water from the soil moves into the root cells by osmosis. Therefore, the correct answer is 'water'.</div>", "topic": "TRANSPORT : NEED FOR TRANSPORTATION"}, {"id": "objective>Biology>2021-Model-II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements define plasmolysis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shrinking of a plant cell in solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shrinking away of cytoplasm from an animal cell membrane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shrinking away of the cytoplasm from the plant cell wall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shrinking of the vacuole and leaving the cytoplasm attached to the cell wall</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plasmolysis is the process in which cells lose water in a hypertonic solution. This leads to the shrinking away of the cytoplasm from the plant cell wall. This is a phenomenon observed in plant cells when placed in a strong saline or sugar solution. Therefore, the correct answer is 'shrinking away of the cytoplasm from the plant cell wall'.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2021-Model-II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a function of the pancreas?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Production of digestive enzymes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Secretion of insulin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Regulation of blood sugar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Storage of bile</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pancreas produces digestive enzymes and hormones like insulin to regulate blood sugar levels. However, it does not store bile. Bile is produced by the liver and stored in the gallbladder, not the pancreas.</div>", "topic": "DIGESTIVE SYSTEM~~SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>2021-Model-II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The role of ATP include all the following activities except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provision of energy to do work in living organisms </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transmission of nerve impulses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">keeping the body warm in homothermic animals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">producing water during aerobic respiration</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ATP (Adenosine Triphosphate) is a molecule that carries energy within cells. It is the main energy currency of the cell, and it is an end product of the processes of photophosphorylation (adding a phosphate group to a molecule using energy from light), cellular respiration, and fermentation. All living things use ATP. However, ATP does not produce water during aerobic respiration. In aerobic respiration, water is produced as a byproduct when oxygen is used to break down glucose for energy.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2021-Model-II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All of the following are essential for an organism's growth except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increase in cell size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Specialization of cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Multiplication of cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shrinking of cells</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Growth in living organisms is supported by three key processes: cell division (multiplication of cells), cell differentiation (specialization of cells), and cell enlargement (increase in cell size). Shrinking of cells is the opposite of growth and does not contribute to development, making it the correct \"except\" option.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>2021-Model-II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is true about movement of the forearm? In</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bending the arm, the biceps relax and the triceps contract</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bending the arm, the biceps contract and the triceps relax </div>", "<div style=\"font-family:Cambria;font-size:17px;\">straightening the arm, the biceps contract and the triceps relax </div>", "<div style=\"font-family:Cambria;font-size:17px;\">straightening the arm, both biceps and triceps contract</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When you bend your arm, your biceps muscle contracts and your triceps muscle relaxes. This is because the biceps and triceps muscles work in pairs to facilitate movement. When one muscle of the pair contracts, the other muscle relaxes. This is known as antagonistic muscle action.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2021-Model-II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Only specially adapted micro-organisms are able to survive in environments with very high temperatures, such as hot springs. These organisms are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Thermophiles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Halophiles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mesophiles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Psychrophiles</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thermophiles are micro-organisms adapted to thrive in extremely hot environments, such as hot springs or hydrothermal vents. Halophiles thrive in salty conditions, mesophiles prefer moderate temperatures, and psychrophiles thrive in cold environments.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2021-Model-II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms causes syphilis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Myeobacterium tuberculosis </span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Bordetella pertusis </span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Treponema pallidum </span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Clostridium tetani </span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Syphilis is caused by the bacterium <span style=\"font-style:italic;\"> Treponema pallidum </span>. This bacterium is a spirochete, a type of bacterium that is long, thin and spiral-shaped. It is capable of burrowing into the lining of the mouth or genital area and causing infection.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2021-Model-II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hypermetropia is corrected by the use of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">concave lenses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">convex lenses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cylindrical lenses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">contact lenses</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hypermetropia, also known as farsightedness, is a condition of the eye where the light that comes in does not directly focus on the retina but behind it. This condition can be corrected by using convex lenses. Convex lenses help to converge the light onto the retina, thus correcting the vision.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2021-Model-II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about short sight is not correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The eyeball is too short</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The cornea of the eye ball is too curved </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The images fall in front of the retina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can be corrected by using concave lenses </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Short sight, also known as myopia, is a condition where the light that comes into the eye does not directly focus on the retina but in front of it. This condition is usually caused by the eyeball being too long, not too short. Therefore, the statement 'The eyeball is too short' is not correct. <br/> In short sight, <br/> - the eyeball is too LONG <br/> - the cornea is too CURVED <br/> - The images fall in front of the retina <br/> - It can be corrected using concave lenses </div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2021-Model-II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The medulla oblongata controls all the following except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heart beat </div>", "<div style=\"font-family:Cambria;font-size:17px;\">breathing rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">blood pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance and postures </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The medulla oblongata is a part of the brain that controls autonomic functions such as heart rate, breathing rate, and blood pressure. However, balance and postures are controlled by the cerebellum, not the medulla oblongata. Therefore, the statement 'balance and postures' is not correct.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2021-Model-II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Glomerular filtrate contains </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">no glucose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">amino acids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">no proteins </div>", "<div style=\"font-family:Cambria;font-size:17px;\">blood cells </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Glomerular filtrate is the liquid that is filtered from the blood into the Bowman's capsule of the kidney. This filtrate contains water, glucose, amino acids, urea, and salts. Therefore, the option 'amino acids' is correct. The glomerular filtrate does contain glucose and proteins, but they are reabsorbed back into the blood in the proximal convoluted tubule of the nephron, so the options 'no glucose' and 'no proteins' are incorrect. Urea is also present in the filtrate, but it is not an option here.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2021-Model-II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a function of the liver in mammals?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Storage of some vitamins </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conversion of glycogen into glucose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deamination of excess nitrogenous substances </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Filtration of urea from the blood </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The liver in mammals performs a variety of functions including the storage of some vitamins, conversion of glycogen into glucose, and deamination of excess nitrogenous substances. However, the liver does not filter urea from the blood. This is the function of the kidneys. Therefore, the option 'Filtration of urea from the blood' is correct.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2021-Model-II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soil factors in an ecosystem are referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">topographic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">climatic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">biotic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">edaphic </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an ecosystem, the soil factors such as soil texture, soil pH, soil fertility, etc., are referred to as 'edaphic' factors. Therefore, the option 'edaphic' is correct. Topographic factors refer to the physical features of the land such as mountains, valleys, etc. Climatic factors refer to the weather conditions such as temperature, rainfall, wind, etc. Biotic factors refer to the living organisms in an ecosystem.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2021-Model-II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The secchi disc is used to measure </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">speed of flow of water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">specific gravity of water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">turbidity of water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">depth of water </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Secchi disc is used to measure the turbidity of water. Turbidity refers to the cloudiness or haziness of a fluid caused by large numbers of individual particles that are generally invisible to the naked eye, similar to smoke in air.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2021-Model-II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dentition of a herbivore is distinct from that of other animals due to the presence of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diastema</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cusps on molar teeth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">canines </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ridges on molar teeth </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dentition of a herbivore is distinct from that of other animals due to the presence of a diastema. A diastema is a gap or space between the teeth. In herbivores, this space is often between the incisors and the molars, which allows for the efficient processing of plant material.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2021-Model-II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The significance of a balanced diet is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maintain constant size of an animal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide good taste in food </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the effectiveness of digestion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide good health for an individual </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The significance of a balanced diet is to provide good health for an individual. A balanced diet provides the nutrients necessary for the body to function effectively. Without a balanced diet, an individual is at risk of various health issues, including malnutrition, obesity, and specific nutrient deficiency diseases.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2021-Model-II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major types of man's finger prints do not include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">arch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compound </div>", "<div style=\"font-family:Cambria;font-size:17px;\">simple </div>", "<div style=\"font-family:Cambria;font-size:17px;\">loop </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major types of fingerprints are loop, whorl, and arch. The 'simple' is not a type of fingerprint. Therefore, the correct answer is option 3.</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2021-Model-II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following scientists was involved in organic evolution?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mendel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lamarck</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Morgan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pasteur</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Jean-Baptiste Lamarck was a French biologist who was an early proponent of the idea that biological evolution occurred and proceeded in accordance with natural laws. He gave the theory of organic evolution, also known as Lamarckism. Therefore, the correct answer is option 2.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2021-Model-II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labelled I is the  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oviduct </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ovary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">uterus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">funnel</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure labelled I is the fallopian tube/oviduct.The fallopian tube, also known as the oviduct, is a paired tube in the human female body that transports mature eggs from the ovaries to the uterus. It is a muscular tube that is about 10-14 cm long and 1 cm in diameter.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2021-Model-II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In which part of the labelled structures does implantation take place?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">VI</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Implantation takes place in the uterus (IV). Implantation is the process by which a fertilized egg attaches itself to the lining of the uterus. It occurs about 6-7 days after fertilization.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2021-Model-II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following indicates the direction of the movement of a sperm introduced into the female reproductive system?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III → II →  I → IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">VI →  V → IV → I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V → IV → I → II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">VI → IV →  I →  III</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">VI →  V → IV → I indicates the direction of flow of sperm introduced into the female reproductive system.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2021-Model-II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the labelled parts is responsible for the release of ripe ovum?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">VI</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ovary, the part labelled III is responsible for the release of ripe ovum (ova). The ovaries are two small, almond-shaped organs that are located in the lower abdomen, one on each side of the uterus. They are responsible for producing and releasing eggs, as well as producing hormones that regulate the menstrual cycle and pregnancy.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2021-Model-II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In fishes, the brooders return to their parent's mouth for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">feeding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">breeding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">protection</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In some species of fish, the young ones return to their parent's mouth for protection when they sense danger. This behavior is known as mouthbrooding. Therefore, the correct answer is option 4.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2021-Model-II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to Charles Darwin's theory of evolution, natural selection involves survival of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">weakest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">most populous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">youngest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fittest </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Charles Darwin's theory of evolution, natural selection involves the survival of the fittest. This means that the individuals who are best adapted to their environment are more likely to survive and reproduce. This process leads to the evolution of species over time as beneficial traits become more common in the population.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2021-Model-II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about sex determination is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the probability of male to female offspring is 1/2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Y chromosome of the father decreases the probability of having a male child to 1/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the XX chromosomes of the mother decreases the probability of having a female child to 3/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the vigour of either parents determine the sex of the offspring</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct statement about sex determination is that the probability of male to female offspring is 1/2. This is because the sex of an offspring is determined by the sex chromosomes that it inherits from its parents. A male has both X and Y chromosomes and can pass either of these to the offspring. A female has two X chromosomes and can only pass an X chromosome. Therefore, the probability of having a male (XY) or female (XX) offspring is 1/2.</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2021-Model-II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The genotypic ratio 1:2:1 in the offspring of a hybrid cross illustrates the law of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">use and disuse </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dominance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">segregation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">linkage</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The genotypic ratio 1:2:1 in the offspring of a hybrid cross illustrates the law of segregation. This law, proposed by Gregor Mendel, states that during the formation of reproductive cells (gametes), pairs of hereditary factors (genes) for a specific trait separate so that offspring receive one factor from each parent. This results in the 1:2:1 genotypic ratio seen in the offspring of a hybrid cross.</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}];
